async function reconcileBatch(batchId) {
  try {
    const batch = await loadBatch(batchId);
    const rows = await db.fetchRows(batch.query);
    const processed = await applyRules(rows, batch.rules);
    await db.save(processed);
    await emitMetrics(batch.id, processed.length);
  } catch (err) {
    next(err);
  }
}
